const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
tasksRoutes = require('./modules/tasks/routes');
commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const { generateId } = require('../../lib/id');

let projects = [];

function getAllProjects() {
  return projects;
}

function createProject(name) {
  const project = { id: generateId(), name, tasks: [], members: [] };
  projects.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  createProject,
};

const { BadRequestError, NotFoundError } = require('../../lib/errors');
const projectsService = require('../projects/service');

function addMember(projectId, userId, role) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    throw new NotFoundError('Project not found');
  }
  const member = { userId, role };
  project.members.push(member);
  return member;
}

module.exports = {
  addMember,
};

const express = require('express');
const service = require('./service');
const { BadRequestError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  let tasks = service.getAllTasks(projectId);
  if (req.query.status === 'done') {
    tasks = tasks.filter(task => task.status === 'done');
  }
  res.json({ tasks });
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;
  if (!title || typeof title !== 'string' || title.trim() === '') {
    throw new BadRequestError('Title is required');
  }
  const task = service.createTask(projectId, title);
  res.status(201).json({ task });
});

module.exports = router;

const express = require('express');
const service = require('./service');
const { BadRequestError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { content } = req.body;
  if (!content || typeof content !== 'string' || content.trim() === '') {
    throw new BadRequestError('Content is required');
  }
  const comment = service.addComment(projectId, taskId, content);
  res.status(201).json({ comment });
});

module.exports = router;

const { BadRequestError, NotFoundError } = require('../../lib/errors');
const projectsService = require('../projects/service');

function addComment(projectId, taskId, content) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    throw new NotFoundError('Project not found');
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    throw new NotFoundError('Task not found');
  }
  const comment = { id: generateId(), content };
  task.comments.push(comment);
  return comment;
}

module.exports = {
  addComment,
};

